<?php
namespace App\Models;use Illuminate\Database\Eloquent\Model;use Illuminate\Database\Eloquent\SoftDeletes;
class SecurityIncident extends Model{use SoftDeletes;protected $fillable=['incident_number','status','severity','source_type','source_id','title','description','assigned_to_id','opened_by_id','resolved_by_id','opened_at','triaged_at','resolved_at','due_at','resolution_summary','metadata','owner_id','escalation_owner_id','sla_due_at','severity_reason','closure_blockers','closure_approved_by_id','closure_approved_at','closure_approval_note','postmortem_required','postmortem_completed_at'];protected function casts():array{return ['opened_at'=>'datetime','triaged_at'=>'datetime','resolved_at'=>'datetime','due_at'=>'datetime','sla_due_at'=>'datetime','closure_approved_at'=>'datetime','postmortem_completed_at'=>'datetime','postmortem_required'=>'boolean','closure_blockers'=>'array','metadata'=>'array'];}public function events(){return $this->hasMany(SecurityIncidentEvent::class)->latest('created_at');}public function evidenceLinks(){return $this->hasMany(SecurityIncidentEvidenceLink::class);}public function tasks(){return $this->hasMany(SecurityIncidentTask::class);}public function playbookRuns(){return $this->hasMany(SecurityIncidentPlaybookRun::class);}public function postmortems(){return $this->hasMany(SecurityIncidentPostmortem::class);}public function correctiveActions(){return $this->hasMany(SecurityIncidentCorrectiveAction::class);}}
